from pathlib import Path
import openpyxl
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)
    # Find leave_tracker.xlsx
    tracker_files = list(workspace.rglob("leave_tracker.xlsx"))
    if not tracker_files:
        return {"pass": False, "score": 0.0, "feedback": "No leave_tracker.xlsx found in workspace"}
    tracker_path = tracker_files[0]
    wb = openpyxl.load_workbook(tracker_path, data_only=True)
    ws = wb.active
    # Find header row
    headers = []
    header_row_idx = None
    for i, row in enumerate(ws.iter_rows(values_only=True), start=1):
        if row and any(str(cell).strip().lower() == "employee id" for cell in row if cell is not None):
            headers = [str(cell).strip() if cell is not None else "" for cell in row]
            header_row_idx = i
            break
    if not headers:
        return {"pass": False, "score": 0.0, "feedback": "Could not find header row with 'Employee ID' column in leave_tracker.xlsx"}
    try:
        emp_id_col = next(i for i, h in enumerate(headers) if h.lower() == "employee id")
    except StopIteration:
        return {"pass": False, "score": 0.0, "feedback": "'Employee ID' column not found in leave_tracker.xlsx headers"}
    # Try to find start date and actual end date columns
    start_col = next((i for i, h in enumerate(headers) if "start" in h.lower() and "date" in h.lower()), None)
    end_col = next((i for i, h in enumerate(headers) if "actual" in h.lower() and "end" in h.lower()), None)

    def date_matches(cell_val, target_year, target_month, target_day):
        """Check if a cell value matches the given date, being generous with formats."""
        if cell_val is None:
            return False
        if isinstance(cell_val, datetime):
            return cell_val.year == target_year and cell_val.month == target_month and cell_val.day == target_day
        s = str(cell_val).strip()
        # Try multiple date formats
        for fmt in ["%Y-%m-%d", "%m/%d/%Y", "%d/%m/%Y", "%Y/%m/%d", "%m-%d-%Y", "%d-%m-%Y",
                     "%B %d, %Y", "%b %d, %Y", "%d %B %Y", "%d %b %Y",
                     "%Y-%m-%d %H:%M:%S", "%m/%d/%Y %H:%M:%S", "%d/%m/%Y %H:%M:%S"]:
            try:
                dt = datetime.strptime(s, fmt)
                if dt.year == target_year and dt.month == target_month and dt.day == target_day:
                    return True
            except ValueError:
                continue
        return False

    def is_preexisting(row):
        """Check if this row matches one of the two pre-existing rows:
        - Start Date: December 2, 2024 and Actual End Date: February 28, 2025
        We allow matching on either start date or end date or both.
        The rubric says the two pre-existing rows have Start Date Dec 2, 2024 AND Actual End Date Feb 28, 2025.
        """
        if start_col is None and end_col is None:
            # Can't verify dates, conservatively treat as pre-existing to avoid false negatives
            return True

        sd_match = True
        ed_match = True

        if start_col is not None:
            sd_match = date_matches(row[start_col], 2024, 12, 2)
        if end_col is not None:
            ed_match = date_matches(row[end_col], 2025, 2, 28)

        return sd_match and ed_match

    r0014_rows = []
    new_r0014_rows = []
    row_number = header_row_idx
    for row in ws.iter_rows(min_row=header_row_idx + 1, values_only=True):
        row_number += 1
        if row is None or all(cell is None for cell in row):
            continue
        emp_id = str(row[emp_id_col]).strip() if row[emp_id_col] is not None else ""
        if emp_id.upper() == "R-0014":
            r0014_rows.append({"row": row_number, "data": str(row)})
            if not is_preexisting(row):
                new_r0014_rows.append({"row": row_number, "data": str(row)})

    if new_r0014_rows:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Found {len(new_r0014_rows)} new row(s) with Employee ID 'R-0014' in leave_tracker.xlsx beyond the pre-existing rows (Start Date Dec 2, 2024, Actual End Date Feb 28, 2025). Total R-0014 rows: {len(r0014_rows)}. New rows: {new_r0014_rows}"
        }
    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"No new rows with Employee ID 'R-0014' found in leave_tracker.xlsx beyond the pre-existing rows with Start Date December 2, 2024 and Actual End Date February 28, 2025. Total R-0014 rows found: {len(r0014_rows)}."
    }

