def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "hfwa_balance_tracker.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open workbook: {e}"}

    ws = wb.active

    # Read all values in row 15
    row_values = []
    for cell in ws[15]:
        row_values.append(cell.value)

    # Expected values
    expected = {
        'R-0014': False,
        '19': False,
        '0': False,
        '43': False,
        'Monday, April 07, 2025': False
    }

    def normalize(val):
        if val is None:
            return None
        return str(val).strip()

    def is_numeric_match(actual, expected_num):
        """Check if actual value matches expected number with tolerance."""
        try:
            actual_f = float(str(actual).strip())
            expected_f = float(expected_num)
            if expected_f == 0:
                return abs(actual_f) < 0.5
            return abs(actual_f - expected_f) / max(abs(expected_f), 1e-9) <= 0.05
        except (ValueError, TypeError):
            return False

    found_details = []

    for cell_val in row_values:
        norm = normalize(cell_val)
        if norm is None:
            continue

        # Check R-0014
        if not expected['R-0014']:
            if norm.upper() == 'R-0014' or 'R-0014' in norm.upper():
                expected['R-0014'] = True
                found_details.append(f"Found 'R-0014' as '{cell_val}'")

        # Check 19
        if not expected['19']:
            if is_numeric_match(cell_val, 19):
                expected['19'] = True
                found_details.append(f"Found '19' as '{cell_val}'")

        # Check 0
        if not expected['0']:
            if is_numeric_match(cell_val, 0):
                expected['0'] = True
                found_details.append(f"Found '0' as '{cell_val}'")

        # Check 43
        if not expected['43']:
            if is_numeric_match(cell_val, 43):
                expected['43'] = True
                found_details.append(f"Found '43' as '{cell_val}'")

        # Check date
        if not expected['Monday, April 07, 2025']:
            # Check various date representations
            norm_lower = norm.lower()
            date_match = False
            # Exact or close string match
            if 'april' in norm_lower and '07' in norm or 'april' in norm_lower and '7' in norm:
                if '2025' in norm:
                    date_match = True
            # Check if it's a datetime object
            if hasattr(cell_val, 'strftime'):
                try:
                    formatted = cell_val.strftime('%A, %B %d, %Y')
                    if 'Monday' in formatted and 'April' in formatted and '07' in formatted and '2025' in formatted:
                        date_match = True
                    # Also check without leading zero
                    formatted2 = cell_val.strftime('%Y-%m-%d')
                    if formatted2 == '2025-04-07':
                        date_match = True
                except:
                    pass
            # Also accept 2025-04-07 or 04/07/2025 etc.
            if '2025-04-07' in norm or '04/07/2025' in norm or '4/7/2025' in norm:
                date_match = True
            if date_match:
                expected['Monday, April 07, 2025'] = True
                found_details.append(f"Found date 'Monday, April 07, 2025' as '{cell_val}'")

    all_raw = [normalize(v) for v in row_values]

    missing = [k for k, v in expected.items() if not v]

    if not missing:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"All expected values found in row 15. Details: {'; '.join(found_details)}. Row values: {all_raw}"
        }
    else:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Missing values in row 15: {missing}. Found: {'; '.join(found_details) if found_details else 'none of the expected values'}. Actual row 15 values: {all_raw}"
        }

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # This rubric checks external services (mailbox.json)
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse mailbox.json: {e}"}

    emails = data.get("emails", [])

    # Find the email with email_id "1" (accept both string and int)
    target_email = None
    for email in emails:
        eid = email.get("email_id")
        if str(eid).strip() == "1":
            target_email = email
            break

    if target_email is None:
        return {"pass": False, "score": 0.0, "feedback": "No email with email_id '1' found in mailbox.json."}

    # Check is_read
    is_read = target_email.get("is_read", False)
    # Be flexible: accept True, "true", "True", 1, "1"
    if isinstance(is_read, str):
        is_read_bool = is_read.strip().lower() in ("true", "1", "yes")
    elif isinstance(is_read, (int, float)):
        is_read_bool = bool(is_read)
    else:
        is_read_bool = bool(is_read)

    # Check starred / is_starred / is_important / flagged — be generous with field name
    starred = None
    for key in ["is_starred", "starred", "is_important", "important", "flagged", "is_flagged"]:
        if key in target_email:
            starred = target_email[key]
            break

    if starred is None:
        starred_bool = False
        starred_found = False
    else:
        starred_found = True
        if isinstance(starred, str):
            starred_bool = starred.strip().lower() in ("true", "1", "yes")
        elif isinstance(starred, (int, float)):
            starred_bool = bool(starred)
        else:
            starred_bool = bool(starred)

    issues = []
    if not is_read_bool:
        issues.append(f"is_read is {target_email.get('is_read')} (expected true)")
    if not starred_found:
        issues.append("No starred/important flag field found on the email")
    elif not starred_bool:
        issues.append(f"Starred/important flag is {starred} (expected true)")

    if not issues:
        return {"pass": True, "score": 1.0, "feedback": f"Email 1 is marked as read (is_read={target_email.get('is_read')}) and starred/important ({starred})."}
    elif is_read_bool and not starred_found:
        # Partial: read but no starred field found — could be schema difference.
        # Be generous: if is_read is satisfied but there's no starred field at all, give partial.
        return {"pass": False, "score": 0.5, "feedback": "Email 1 is marked as read, but no starred/important field was found. Issues: " + "; ".join(issues)}
    else:
        score = 0.0
        if is_read_bool:
            score += 0.5
        if starred_found and starred_bool:
            score += 0.5
        return {"pass": False, "score": score, "feedback": "Issues found: " + "; ".join(issues)}

