    if external_services_path is not None:
        candidate = Path(external_services_path) / "slack_data.json"
        if candidate.exists():
            slack_file = candidate

    # Fallback: check workspace
    if slack_file is None:
        candidate = Path(workspace_path) / "slack_data.json"
        if candidate.exists():
            slack_file = candidate

    if slack_file is None:
        # If we can't find slack_data.json at all, we can't confirm the message exists,
        # so technically the condition "must NOT be a message containing X" is satisfied.
        # But let's be cautious and pass since absence of the file means absence of the message.
        return {"pass": True, "score": 1.0, "feedback": "PASS: Could not find slack_data.json; therefore no message containing the target string exists."}

    try:
        with open(slack_file, 'r', encoding='utf-8') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read/parse slack_data.json: {e}"}

    target_string = "FMLA INTAKE: LC-2025-1016"
    found_messages = []

    # Use the documented Slack data format:
    # slack_data["messages"] is a dict keyed by channel ID -> list of message objects
    messages_by_channel = {}
    if isinstance(slack_data, dict):
        if "messages" in slack_data and isinstance(slack_data["messages"], dict):
            messages_by_channel = slack_data["messages"]
        elif "channels" in slack_data and isinstance(slack_data["channels"], dict):
            # Fallback: maybe channels contain messages directly
            messages_by_channel = slack_data["channels"]

    # Search through ALL channels for the target string
    for channel_id, channel_messages in messages_by_channel.items():
        msgs = []
        if isinstance(channel_messages, list):
            msgs = channel_messages
        elif isinstance(channel_messages, dict):
            if "messages" in channel_messages:
                msgs = channel_messages["messages"] if isinstance(channel_messages["messages"], list) else []

        for msg in msgs:
            msg_text = ""
            if isinstance(msg, dict):
                # Check common fields: text, message, body, content
                for key in ["text", "message", "body", "content"]:
                    if key in msg:
                        msg_text += str(msg[key]) + " "
            elif isinstance(msg, str):
                msg_text = msg

            if target_string in msg_text:
                found_messages.append((channel_id, msg_text.strip()))

    # Also do a brute-force search of the entire JSON string as a safety net
    raw_text = json.dumps(slack_data)
    brute_force_found = target_string in raw_text

    if len(found_messages) > 0:
        return {
            "pass": False,
            "score": 0.0,
