    elif brute_force_found and len(found_messages) == 0:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"FAIL: The string \"{target_string}\" was found somewhere in slack_data.json (brute-force search), even though structured message parsing did not find it. The rubric requires it must NOT exist."
        }
    else:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": f"PASS: No messages containing \"{target_string}\" were found anywhere in slack_data.json."
        }

