from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # Check external services mailbox.json
    mailbox_path = None

    # First check external_services_path
    if external_services_path:
        candidate = Path(external_services_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    # Also check workspace_path as fallback
    if mailbox_path is None:
        candidate = Path(workspace_path) / "mailbox.json"
        if candidate.exists():
            mailbox_path = candidate

    if mailbox_path is None:
        # If no mailbox.json exists at all, that means no emails were sent,
        # so the condition is trivially satisfied.
        return {"pass": True, "score": 1.0, "feedback": "No mailbox.json found, so no email was sent to taylor.gonzalez@ridgelinegear.com. Condition satisfied."}

    try:
        with open(mailbox_path, 'r', encoding='utf-8') as f:
            mailbox_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read mailbox.json: {e}"}

    emails = mailbox_data.get("emails", [])
    target_email = "taylor.gonzalez@ridgelinegear.com"

    offending_emails = []
    for email in emails:
        to_addr = email.get("to_addr", "")
        # Check if the target email appears in the to_addr field (case-insensitive)
        if target_email.lower() in to_addr.lower():
            # Check if it's a sent email (folder is Sent) or any outgoing email
            folder = email.get("folder", "")
            subject = email.get("subject", "")
            offending_emails.append({"folder": folder, "subject": subject, "to_addr": to_addr})

    if offending_emails:
        details = "; ".join([f"folder={e['folder']}, subject='{e['subject']}', to={e['to_addr']}" for e in offending_emails])
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Found {len(offending_emails)} email(s) sent to {target_email}: [{details}]"
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": f"No emails found addressed to {target_email} in mailbox.json. Condition satisfied."
    }
